'use client'

import { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { createClient } from '@/lib/supabaseClient'
import toast from 'react-hot-toast'
import {
  APPEARANCE_DEFAULTS,
  type AppearanceSettings,
  getAppSettings,
  saveAppSettings,
} from '@/lib/appSettings'

const FONTS = ['Cairo', 'Tajawal', 'Inter'] as const

const PRESET_PALETTES = [
  { label: 'Void Purple (Default)', primary: '#7c3aed', accent: '#f59e0b', bg: '#04040f' },
  { label: 'Ocean Blue',            primary: '#2563eb', accent: '#06b6d4', bg: '#040f1a' },
  { label: 'Rose Gold',             primary: '#e11d48', accent: '#f97316', bg: '#0f0406' },
  { label: 'Emerald Night',         primary: '#059669', accent: '#8b5cf6', bg: '#02100a' },
  { label: 'Cyber Yellow',          primary: '#ca8a04', accent: '#3b82f6', bg: '#0a0900' },
]

function ColorSwatch({ label, value, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
  return (
    <div className="card-glass flex items-center gap-4 p-4">
      <div className="relative">
        <input
          type="color"
          value={value}
          onChange={e => onChange(e.target.value)}
          className="w-12 h-12 rounded-xl border border-white/10 cursor-pointer bg-transparent p-0.5"
        />
      </div>
      <div className="flex-1">
        <p className="text-sm font-bold" style={{ color: 'var(--color-text-primary)' }}>{label}</p>
        <p className="text-xs font-mono mt-0.5" style={{ color: 'var(--color-text-muted)' }}>{value}</p>
      </div>
      <div className="w-8 h-8 rounded-full border border-white/10" style={{ backgroundColor: value }} />
    </div>
  )
}

function Toggle({ label, desc, checked, onChange }: { label: string; desc?: string; checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <div className="flex items-center justify-between gap-4 py-3 border-b" style={{ borderColor: 'var(--color-border)' }}>
      <div>
        <p className="text-sm font-bold" style={{ color: 'var(--color-text-primary)' }}>{label}</p>
        {desc && <p className="text-xs mt-0.5" style={{ color: 'var(--color-text-muted)' }}>{desc}</p>}
      </div>
      <button
        onClick={() => onChange(!checked)}
        className={`relative w-11 h-6 rounded-full transition-colors duration-200 focus:outline-none shrink-0 ${checked ? 'bg-purple-600' : 'bg-white/10'}`}
      >
        <span className={`absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow transition-transform duration-200 ${checked ? 'translate-x-5' : 'translate-x-0'}`} />
      </button>
    </div>
  )
}

function ThemeSelector({ value, onChange }: { value: 'light' | 'dark' | 'system'; onChange: (v: 'light' | 'dark' | 'system') => void }) {
  const options = [
    { value: 'light',  label: '┘å┘ç╪º╪▒┘è (Light)',  icon: 'ΓÿÇ∩╕Å' },
    { value: 'dark',   label: '┘ä┘è┘ä┘è (Dark)',   icon: '≡ƒîÖ' },
    { value: 'system', label: '╪¬┘ä┘é╪º╪ª┘è (System)', icon: '≡ƒûÑ∩╕Å' },
  ] as const

  return (
    <div className="flex gap-2">
      {options.map(opt => (
        <button
          key={opt.value}
          onClick={() => onChange(opt.value)}
          className={`flex-1 flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${
            value === opt.value
              ? 'bg-purple-600/20 border-purple-500/50 text-purple-400'
              : 'bg-white/5 border-white/10 text-white/40 hover:bg-white/10'
          }`}
        >
          <span className="text-xl">{opt.icon}</span>
          <span className="text-[10px] font-black uppercase tracking-wider">{opt.label}</span>
        </button>
      ))}
    </div>
  )
}

export default function AdminAppearancePage() {
  const supabase = createClient()
  const [settings, setSettings] = useState<AppearanceSettings>(APPEARANCE_DEFAULTS)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    getAppSettings('appearance', APPEARANCE_DEFAULTS, supabase).then(s => {
      setSettings(s)
      setLoading(false)
    })
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  function set<K extends keyof AppearanceSettings>(key: K, value: AppearanceSettings[K]) {
    setSettings(s => ({ ...s, [key]: value }))
  }

  async function save() {
    setSaving(true)
    const { error } = await saveAppSettings('appearance', settings, supabase)
    if (error) toast.error('╪«╪╖╪ú ┘ü┘è ╪º┘ä╪¡┘ü╪╕: ' + error.message)
    else toast.success('╪¬┘à ╪¡┘ü╪╕ ╪Ñ╪╣╪»╪º╪»╪º╪¬ ╪º┘ä┘à╪╕┘ç╪▒ Γ£ô ΓÇö ╪│╪¬┘Å╪╖╪¿┘é ╪╣┘å╪» ╪Ñ╪╣╪º╪»╪⌐ ╪¬╪¡┘à┘è┘ä ╪º┘ä╪╡┘ü╪¡╪⌐')
    setSaving(false)
  }

  function applyPreset(p: typeof PRESET_PALETTES[0]) {
    setSettings(s => ({ ...s, primary_color: p.primary, accent_color: p.accent, bg_color: p.bg }))
  }

  if (loading) return (
    <div className="p-8 space-y-4">
      {Array(5).fill(0).map((_, i) => <div key={i} className="h-16 card-glass animate-shimmer rounded-2xl" />)}
    </div>
  )

  return (
    <div className="p-8 max-w-3xl space-y-10">

      {/* Header */}
      <div>
        <h1 className="text-3xl font-black gradient-text-primary">╪º┘ä┘à╪╕┘ç╪▒ ┘ê╪º┘ä╪ú┘ä┘ê╪º┘å</h1>
        <p style={{ color: 'var(--color-text-secondary)' }}>
          ╪¬╪¡┘â┘à ┘ü┘è ╪ú┘ä┘ê╪º┘å ╪º┘ä┘à┘å╪╡╪⌐╪î ╪º┘ä╪«╪╖┘ê╪╖╪î ┘ê╪º┘ä╪¬╪ú╪½┘è╪▒╪º╪¬ ╪º┘ä╪¿╪╡╪▒┘è╪⌐. ╪º┘ä╪¬╪║┘è┘è╪▒╪º╪¬ ╪¬┘Å╪╖╪¿┘é ╪╣┘å╪» ╪Ñ╪╣╪º╪»╪⌐ ╪¬╪¡┘à┘è┘ä ╪ú┘è ╪╡┘ü╪¡╪⌐.
        </p>
      </div>

      {/* Palette Presets */}
      <section className="space-y-4">
        <h2 className="text-lg font-black" style={{ color: 'var(--color-text-primary)' }}>
          ╪ú┘ä┘ê╪º┘å ╪¼╪º┘ç╪▓╪⌐ (Presets)
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {PRESET_PALETTES.map(p => {
            const active = p.primary === settings.primary_color && p.accent === settings.accent_color
            return (
              <motion.button
                key={p.label}
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => applyPreset(p)}
                className="card-glass p-4 text-right transition-all"
                style={{
                  border: active ? `2px solid ${p.primary}` : '2px solid transparent',
                  boxShadow: active ? `0 0 20px ${p.primary}33` : 'none',
                }}
              >
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-5 h-5 rounded-full" style={{ background: p.bg, border: '1px solid rgba(255,255,255,0.1)' }} />
                  <div className="w-5 h-5 rounded-full" style={{ background: p.primary }} />
                  <div className="w-5 h-5 rounded-full" style={{ background: p.accent }} />
                  {active && <span className="mr-auto text-xs font-bold" style={{ color: p.primary }}>Γ£ô ┘å╪┤╪╖</span>}
                </div>
                <p className="text-xs font-bold" style={{ color: 'var(--color-text-secondary)' }}>{p.label}</p>
              </motion.button>
            )
          })}
        </div>
      </section>

      {/* Custom Colors */}
      <section className="space-y-3">
        <h2 className="text-lg font-black" style={{ color: 'var(--color-text-primary)' }}>╪º┘ä╪ú┘ä┘ê╪º┘å ╪º┘ä┘à╪«╪╡╪╡╪⌐</h2>
        <ColorSwatch label="╪º┘ä┘ä┘ê┘å ╪º┘ä╪▒╪ª┘è╪│┘è (Primary)"  value={settings.primary_color} onChange={v => set('primary_color', v)} />
        <ColorSwatch label="╪º┘ä┘ä┘ê┘å ╪º┘ä╪½╪º┘å┘ê┘è (Accent)"   value={settings.accent_color}  onChange={v => set('accent_color', v)} />
        <ColorSwatch label="┘ä┘ê┘å ╪º┘ä╪«┘ä┘ü┘è╪⌐ (Background)" value={settings.bg_color}       onChange={v => set('bg_color', v)} />
      </section>

      {/* Live Color Preview */}
      <section>
        <h2 className="text-lg font-black mb-3" style={{ color: 'var(--color-text-primary)' }}>┘à╪╣╪º┘è┘å╪⌐ ╪º┘ä╪ú┘ä┘ê╪º┘å</h2>
        <div className="rounded-2xl overflow-hidden border" style={{ borderColor: 'var(--color-border)', backgroundColor: settings.bg_color }}>
          <div className="p-6 space-y-4">
            <div className="h-10 rounded-xl w-2/3" style={{ background: `linear-gradient(135deg, ${settings.primary_color}, ${settings.accent_color})` }} />
            <div className="flex gap-3">
              <div className="h-8 rounded-lg flex-1" style={{ background: `${settings.primary_color}22`, border: `1px solid ${settings.primary_color}44` }} />
              <div className="h-8 w-24 rounded-lg" style={{ background: settings.primary_color }} />
            </div>
            <div className="h-2 rounded-full w-full" style={{ background: `${settings.accent_color}33` }}>
              <div className="h-2 rounded-full w-1/2" style={{ background: settings.accent_color }} />
            </div>
            <p className="text-xs font-mono" style={{ color: settings.primary_color }}>Primary: {settings.primary_color} ┬╖ Accent: {settings.accent_color}</p>
          </div>
        </div>
      </section>

      {/* Theme Mode */}
      <section className="space-y-3">
        <h2 className="text-lg font-black" style={{ color: 'var(--color-text-primary)' }}>┘å┘à╪╖ ╪º┘ä┘à╪╕┘ç╪▒ (Theme)</h2>
        <ThemeSelector value={settings.theme_mode} onChange={v => set('theme_mode', v)} />
        <p className="text-[10px] uppercase tracking-widest font-bold opacity-30 mt-1">
          * ╪º┘ä┘ê╪╢╪╣ ╪º┘ä╪¬┘ä┘é╪º╪ª┘è ┘è╪¬╪¿╪╣ ╪Ñ╪╣╪»╪º╪»╪º╪¬ ╪¼┘ç╪º╪▓ ╪º┘ä┘à╪│╪¬╪«╪»┘à
        </p>
      </section>

      {/* Font */}
      <section className="space-y-3">
        <h2 className="text-lg font-black" style={{ color: 'var(--color-text-primary)' }}>╪º┘ä╪«╪╖ (Font)</h2>
        <div className="card-glass p-4 flex items-center gap-4">
          <span className="text-2xl">≡ƒöñ</span>
          <div className="flex-1">
            <label className="label mb-1">╪«╪╖ ╪º┘ä╪¼╪│┘à ╪º┘ä╪▒╪ª┘è╪│┘è</label>
            <select
              className="input"
              value={settings.font_body}
              onChange={e => set('font_body', e.target.value as any)}
            >
              {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
            </select>
          </div>
          <p className="text-lg font-bold shrink-0" style={{ fontFamily: settings.font_body, color: 'var(--color-text-secondary)' }}>
            ╪ú╪¿╪¼╪» ┘ç┘ê╪▓
          </p>
        </div>
      </section>

      {/* Visual Effects */}
      <section>
        <h2 className="text-lg font-black mb-1" style={{ color: 'var(--color-text-primary)' }}>╪º┘ä╪¬╪ú╪½┘è╪▒╪º╪¬ ╪º┘ä╪¿╪╡╪▒┘è╪⌐</h2>
        <div className="card-glass px-4">
          <Toggle
            label="╪¼╪│┘è┘à╪º╪¬ ╪º┘ä╪«┘ä┘ü┘è╪⌐ (Particles)"
            desc="╪¬╪ú╪½┘è╪▒ ╪º┘ä╪¼╪▓┘è╪ª╪º╪¬ ╪º┘ä┘à╪¬╪╖╪º┘è╪▒╪⌐ ┘ü┘è ╪«┘ä┘ü┘è╪⌐ ╪º┘ä╪╡┘ü╪¡╪⌐"
            checked={settings.particles_enabled}
            onChange={v => set('particles_enabled', v)}
          />
          <Toggle
            label="╪┤╪¿┘â╪⌐ ╪º┘ä╪«┘ä┘ü┘è╪⌐ (Grid)"
            desc="╪«╪╖┘ê╪╖ ╪º┘ä╪┤╪¿┘â╪⌐ ╪º┘ä╪«┘ü┘è┘ü╪⌐ ┘ü┘è ╪º┘ä╪«┘ä┘ü┘è╪⌐"
            checked={settings.grid_enabled}
            onChange={v => set('grid_enabled', v)}
          />
          <Toggle
            label="╪╖╪¿┘é╪⌐ ╪º┘ä╪╢┘ê╪╢╪º╪í (Noise Overlay)"
            desc="╪╖╪¿┘é╪⌐ ╪¡╪¿┘è╪¿┘è╪⌐ ╪«┘ü┘è╪⌐ ╪¬╪╢┘è┘ü ╪╣┘à┘é╪º┘ï ╪¿╪╡╪▒┘è╪º┘ï"
            checked={settings.noise_enabled}
            onChange={v => set('noise_enabled', v)}
          />
        </div>
      </section>

      {/* Save */}
      <button
        onClick={save}
        disabled={saving}
        className="btn btn-primary btn-lg w-full"
      >
        {saving ? 'ΓÅ│ ╪¼╪º╪▒┘è ╪º┘ä╪¡┘ü╪╕...' : '≡ƒÆ╛ ╪¡┘ü╪╕ ╪Ñ╪╣╪»╪º╪»╪º╪¬ ╪º┘ä┘à╪╕┘ç╪▒'}
      </button>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { createClient } from '@/lib/supabaseClient'
import toast from 'react-hot-toast'
import MediaCropEditor, { type CropConfig } from '@/components/MediaCropEditor'

const ICONS = ['≡ƒôÜ','≡ƒîì','≡ƒö¼','≡ƒô£','ΓÜ╜','≡ƒÄ¼','≡ƒºá','≡ƒÄ╡','≡ƒìö','≡ƒÅ¢∩╕Å','≡ƒÆ╗','Γ£ê∩╕Å','≡ƒÉ╛','≡ƒº⌐','≡ƒÄ»']

export default function AdminCategoriesPage() {
  const supabase = createClient()
  const [cats, setCats] = useState<any[]>([])
  const [topics, setTopics] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [modal, setModal] = useState(false)
  const [editing, setEditing] = useState<any | null>(null)
  const [form, setForm] = useState({ id: '', name: '', icon: '≡ƒôÜ', topic_id: '', image_url: '', hide_icon: false })
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [deleteId, setDeleteId] = useState<string | null>(null)
  const [cropEditorUrl, setCropEditorUrl] = useState<string | null>(null)
  const [cropConfig, setCropConfig] = useState<CropConfig | null>(null)

  async function load() {
    const [catsRes, topicsRes] = await Promise.all([
      (supabase.from('categories') as any).select('*, topics(name, color), questions(count)').order('name'),
      (supabase.from('topics') as any).select('id, name').order('order_index')
    ])
    
    setCats(catsRes.data ?? [])
    setTopics(topicsRes.data ?? [])
    setLoading(false)
  }
  useEffect(() => { load() }, [])

  function openAdd() { 
    setForm({ id: `cat-${Date.now()}`, name: '', icon: '≡ƒôÜ', topic_id: topics[0]?.id || '', image_url: '', hide_icon: false })
    setEditing(null)
    setModal(true) 
  }
  function openEdit(c: any) { 
    setForm({ id: c.id, name: c.name, icon: c.icon ?? '≡ƒôÜ', topic_id: c.topic_id || '', image_url: c.image_url || '', hide_icon: c.hide_icon || false })
    setCropConfig(c.crop_config || null)
    setEditing(c)
    setModal(true) 
  }

  async function handleImageUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return

    setUploading(true)
    const fileExt = file.name.split('.').pop()
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`
    const filePath = `category_backgrounds/${fileName}`

    try {
      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file)

      if (uploadError) throw uploadError

      const { data } = supabase.storage
        .from('images')
        .getPublicUrl(filePath)

      setForm(f => ({ ...f, image_url: data.publicUrl }))
      setCropEditorUrl(data.publicUrl)  // Auto-open crop editor after upload
      toast.success('╪¬┘à ╪▒┘ü╪╣ ╪º┘ä╪╡┘ê╪▒╪⌐ ╪¿┘å╪¼╪º╪¡! ╪º╪╢╪¿╪╖ ╪º┘ä┘é╪╡ ╪º┘ä╪ó┘å.')
    } catch (error: any) {
      toast.error('╪«╪╖╪ú ┘ü┘è ╪º┘ä╪▒┘ü╪╣: ' + error.message)
    } finally {
      setUploading(false)
    }
  }

  async function save() {
    if (!form.name.trim()) { toast.error('╪º╪│┘à ╪º┘ä┘ü╪ª╪⌐ ┘à╪╖┘ä┘ê╪¿'); return }
    setSaving(true)
    const payload = { 
      id: form.id,
      name: form.name.trim(), 
      icon: form.icon, 
      topic_id: form.topic_id || null, 
      image_url: form.image_url, 
      hide_icon: form.hide_icon,
      crop_config: cropConfig || null
    }
    const { error } = editing
      ? await (supabase.from('categories') as any).update(payload).eq('id', editing.id)
      : await (supabase.from('categories') as any).insert(payload)
    if (error) { toast.error(error.message); setSaving(false); return }
    toast.success(editing ? '╪¬┘à ╪º┘ä╪¬╪¡╪»┘è╪½' : '╪¬┘à╪¬ ╪º┘ä╪Ñ╪╢╪º┘ü╪⌐')
    setModal(false); setSaving(false); load()
  }

  async function del(id: string) {
    const { error } = await (supabase.from('categories') as any).delete().eq('id', id)
    if (error) { toast.error(error.message); return }
    toast.success('╪¬┘à ╪º┘ä╪¡╪░┘ü'); setDeleteId(null); load()
  }

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-black gradient-text-primary">╪º┘ä┘ü╪ª╪º╪¬</h1>
          <p style={{ color: 'var(--color-text-secondary)' }}>{cats.length} ┘ü╪ª╪⌐</p>
        </div>
        <button onClick={openAdd} className="btn btn-primary">+ ╪Ñ╪╢╪º┘ü╪⌐ ┘ü╪ª╪⌐</button>
      </div>

      {loading ? (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {Array(6).fill(0).map((_, i) => <div key={i} className="h-28 card-glass animate-shimmer rounded-2xl" />)}
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
          {cats.map((c, i) => (
            <motion.div
              key={c.id}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              className="card-glass flex items-center gap-4 relative overflow-hidden"
            >
              <div className="absolute top-0 bottom-0 right-0 w-1 z-10" style={{ backgroundColor: c.topics?.color || '#3b82f6' }} />
              {c.image_url && (
                <div 
                  className="absolute inset-0 bg-cover bg-center opacity-30 z-0 pointer-events-none" 
                  style={{ backgroundImage: `url(${c.image_url})` }} 
                />
              )}
              <div className="text-4xl w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 mr-2 z-10 relative"
                style={{ background: 'var(--color-surface-3)' }}>
                {c.icon}
              </div>
              <div className="flex-1 min-w-0 z-10 relative">
                <p className="font-bold truncate" style={{ color: 'var(--color-text-primary)' }}>{c.name}</p>
                <div className="flex items-center gap-2 mt-1">
                  {c.topics && (
                    <span className="text-[10px] px-2 py-0.5 rounded-md" style={{ background: `${c.topics.color}20`, color: c.topics.color }}>
                      {c.topics.name}
                    </span>
                  )}
                  <p className="text-xs" style={{ color: 'var(--color-text-muted)' }}>
                    {c.questions?.[0]?.count ?? 0} ╪│╪ñ╪º┘ä
                  </p>
                </div>
              </div>
              <div className="flex flex-col gap-1">
                <button onClick={() => openEdit(c)} className="btn btn-sm btn-ghost" style={{ padding: '4px 10px', fontSize: '12px' }}>╪¬╪╣╪»┘è┘ä</button>
                <button onClick={() => setDeleteId(c.id)} className="btn btn-sm" style={{ padding: '4px 10px', fontSize: '12px', background: 'rgba(239,68,68,0.1)', color: '#ef4444', border: '1px solid rgba(239,68,68,0.2)' }}>╪¡╪░┘ü</button>
              </div>
            </motion.div>
          ))}
          {cats.length === 0 && (
            <div className="col-span-3 py-16 text-center" style={{ color: 'var(--color-text-muted)' }}>
