              </div>
              <div>
                <label className="label">╪º┘ä╪│╪ñ╪º┘ä *</label>
                <textarea className="input" rows={3} value={form.question} onChange={e => setForm(f => ({ ...f, question: e.target.value }))} placeholder="╪º┘â╪¬╪¿ ╪º┘ä╪│╪ñ╪º┘ä..." />
              </div>
