function getPasswordStrength(pw: string): PasswordStrength {
  if (!pw) return { score: 0, label: '', color: '' }
  let s = 0
  if (pw.length >= 8)           s++
  if (pw.length >= 12)          s++
  if (/[A-Z]/.test(pw))        s++
  if (/[0-9]/.test(pw))        s++
  if (/[^A-Za-z0-9]/.test(pw)) s++

  if (s <= 1) return { score: 1, label: '╪╢╪╣┘è┘ü╪⌐ ╪¼╪»╪º┘ï', color: '#ef4444' }
  if (s <= 3) return { score: 2, label: '┘à╪¬┘ê╪│╪╖╪⌐',     color: '#f59e0b' }
  return              { score: 3, label: '┘é┘ê┘è╪⌐ ≡ƒÆ¬',    color: '#22c55e' }
}

function formatBirthdate(raw: string): string {
  if (!raw) return ''
  const [y, m, d] = raw.split('-')
  return `${parseInt(d)} ${MONTHS[parseInt(m) - 1]} ${y}`
}

