'use client'

import { motion } from 'framer-motion'
import { useEffect, useState } from 'react'
import type { MascotState } from '@/types/game'

// Standardized team color palette
export const TEAM_PALETTE = [
  { color: '#FF3B3B', glow: 'rgba(255,59,59,0.6)',   dark: '#8B0000', label: '╪ú╪¡┘à╪▒'   },
  { color: '#3B82F6', glow: 'rgba(59,130,246,0.6)',  dark: '#1E3A8A', label: '╪ú╪▓╪▒┘é'   },
  { color: '#A855F7', glow: 'rgba(168,85,247,0.6)',  dark: '#4C1D95', label: '╪¿┘å┘ü╪│╪¼┘è' },
  { color: '#22C55E', glow: 'rgba(34,197,94,0.6)',   dark: '#14532D', label: '╪ú╪«╪╢╪▒'   },
]

interface Props {
  state?: MascotState
  size?: number
  className?: string
  isTalking?: boolean
  color?: string  // Base team color e.g. '#FF3B3B'
  expandBody?: boolean
}

export default function Mascot({
  state = 'idle',
  size = 160,
  className = '',
  isTalking = false,
  color = '#3B82F6',
  expandBody = false,
}: Props) {
  const [mouthOpen, setMouthOpen] = useState(false)
  const uid = color.replace('#', 'c')

  // Derive dark variant for gradient end stop
  const palette = TEAM_PALETTE.find(p => p.color.toLowerCase() === color.toLowerCase())
  const darkColor = palette?.dark || '#000000'

  useEffect(() => {
    if (!isTalking) { setMouthOpen(false); return }
    const interval = setInterval(() => setMouthOpen(p => !p), 130)
    return () => clearInterval(interval)
  }, [isTalking])

  const containerVariants: any = {
    idle:       { y: [0, -5, 0],         transition: { duration: 3, repeat: Infinity, ease: 'easeInOut' } },
    correct:    { y: [0, -22, 0, -10, 0], scale: [1, 1.08, 1], transition: { duration: 0.6 } },
    wrong:      { x: [-8, 8, -8, 8, 0],   transition: { duration: 0.4 } },
    punishment: { rotate: [-6, 6, -6, 6, 0], scale: [1, 0.92, 1], transition: { duration: 0.45 } },
    thinking:   { x: [0, -4, 0], y: [0, -3, 0], transition: { duration: 2.2, repeat: Infinity } },
    hype:       { y: [0, -24, 0], scale: [1, 1.1, 1], transition: { duration: 0.38, repeat: Infinity } },
    angry:      { scale: [1, 1.05, 1], y: [0, -2, 0], transition: { duration: 0.22, repeat: Infinity, repeatType: 'mirror' as any } },
    sad:        { y: [0, 4, 0], opacity: 0.8, transition: { duration: 4, repeat: Infinity, ease: 'easeInOut' } },
  }


  const eyebrowV: any = {
    idle:       { y: 0, rotate: 0 },
    correct:    { y: -5, rotate: 0 },
    wrong:      { y: 3, rotate: 0 },
    punishment: { y: 4, rotate: 14 },
    thinking:   { y: [-1, 2, -1], rotate: [-3, 3, -3], transition: { repeat: Infinity, duration: 2 } },
    hype:       { y: -7, rotate: 0 },
    angry:      { y: 4, rotate: 18 },
    sad:        { y: 2, rotate: -10 },
  }

  // Limb / feature stroke color ΓÇö always near-black for minimalist doodle look
  const INK = '#111111'

  return (
    <motion.div
      key={state}
      variants={containerVariants}
      animate={state}
      className={`relative flex items-end justify-center select-none ${className}`}
      style={{ width: size, height: size * 1.28 }}
    >
      <svg width="100%" height="100%" viewBox="0 0 200 256" fill="none" xmlns="http://www.w3.org/2000/svg" style={{ overflow: 'visible' }}>
        <defs>
          {/* 3-stop radial gradient: bright highlight ΓåÆ vivid base ΓåÆ deep dark */}
          <radialGradient id={`bg-${uid}`} cx="35%" cy="28%" r="75%">
            <stop offset="0%"   stopColor="white"     stopOpacity="0.6" />
            <stop offset="45%"  stopColor={color}     stopOpacity="1" />
            <stop offset="100%" stopColor={darkColor}  stopOpacity="1" />
          </radialGradient>
          {/* Extra vivid inner glow */}
          <radialGradient id={`vg-${uid}`} cx="40%" cy="32%" r="55%">
            <stop offset="0%"   stopColor={color} stopOpacity="0.7" />
            <stop offset="100%" stopColor={color} stopOpacity="0" />
          </radialGradient>
          <filter id={`glow-${uid}`} x="-30%" y="-30%" width="160%" height="160%">
            <feDropShadow dx="0" dy="4" stdDeviation="10" floodColor={color} floodOpacity="0.7" />
          </filter>
        </defs>



        {/* ΓöÇΓöÇ PERFECT CIRCLE BODY ΓöÇΓöÇ vivid radial gradient */}
        <motion.circle cx="100" cy="104" r="70" fill={`url(#bg-${uid})`} filter={`url(#glow-${uid})`} 
          animate={expandBody ? { scale: 80 } : { scale: 1 }}
          transition={{ duration: 0.75, ease: [0.16, 1, 0.3, 1] }}
          style={{ originX: '100px', originY: '104px' }}
        />
        {/* Extra inner glow layer for vividness */}
        <motion.circle cx="100" cy="104" r="70" fill={`url(#vg-${uid})`} 
          animate={expandBody ? { scale: 80 } : { scale: 1 }}
          transition={{ duration: 0.75, ease: [0.16, 1, 0.3, 1] }}
          style={{ originX: '100px', originY: '104px' }}
        />
        {/* Subtle dark outline */}
        <motion.circle cx="100" cy="104" r="70" stroke={INK} strokeWidth="1.5" strokeOpacity="0.12" fill="none" 
          animate={expandBody ? { scale: 80, opacity: 0 } : { scale: 1, opacity: 1 }}
          transition={{ duration: 0.75, ease: [0.16, 1, 0.3, 1] }}
          style={{ originX: '100px', originY: '104px' }}
        />

        <motion.g animate={{ opacity: expandBody ? 0 : 1 }} transition={{ duration: 0.3, ease: 'easeOut' }}>
        {/* ΓöÇΓöÇ EYES ΓöÇΓöÇ */}
        {state === 'correct' || state === 'hype' ? (
          /* Happy arcs */
          <>
            <path d="M76 100 Q85 90 94 100" stroke={INK} strokeWidth="3.5" strokeLinecap="round" fill="none" />
            <path d="M106 100 Q115 90 124 100" stroke={INK} strokeWidth="3.5" strokeLinecap="round" fill="none" />
          </>
        ) : state === 'wrong' || state === 'punishment' ? (
          /* X eyes */
          <>
            <path d="M74 93 L90 107 M90 93 L74 107" stroke={INK} strokeWidth="3.5" strokeLinecap="round" />
            <path d="M110 93 L126 107 M126 93 L110 107" stroke={INK} strokeWidth="3.5" strokeLinecap="round" />
          </>
        ) : state === 'angry' ? (
          /* Squinted slits */
          <>
            <path d="M75 102 Q84 106 93 102" stroke={INK} strokeWidth="4" strokeLinecap="round" fill="none" />
            <path d="M107 102 Q116 106 125 102" stroke={INK} strokeWidth="4" strokeLinecap="round" fill="none" />
          </>
        ) : state === 'thinking' ? (
          /* One squinted, one dot */
          <>
            <path d="M75 102 Q84 106 93 102" stroke={INK} strokeWidth="4" strokeLinecap="round" fill="none" />
            <circle cx="116" cy="100" r="6" fill={INK} />
          </>
        ) : state === 'sad' ? (
          /* Downward squint/sad eyes */
          <>
            <path d="M76 104 Q85 110 94 104" stroke={INK} strokeWidth="3" strokeLinecap="round" fill="none" />
            <path d="M106 104 Q115 110 124 104" stroke={INK} strokeWidth="3" strokeLinecap="round" fill="none" />
          </>
        ) : (
          /* Normal dots with blink */
          <>
            <circle cx="84" cy="100" r="6" fill={INK} />
            <circle cx="116" cy="100" r="6" fill={INK} />
            <motion.rect x="78" y="94" width="12" height="12" fill={color} rx="6"
              animate={{ scaleY: [0, 1, 0] }}
              transition={{ duration: 0.12, repeat: Infinity, repeatDelay: 4 }}
              style={{ transformOrigin: '84px 100px' }}
            />
            <motion.rect x="110" y="94" width="12" height="12" fill={color} rx="6"
              animate={{ scaleY: [0, 1, 0] }}
              transition={{ duration: 0.12, repeat: Infinity, repeatDelay: 4 }}
              style={{ transformOrigin: '116px 100px' }}
            />
          </>
        )}

        {/* ΓöÇΓöÇ EYEBROWS ΓöÇΓöÇ */}
        <motion.g variants={eyebrowV} animate={state} style={{ originX: '100px', originY: '88px' }}>
          {state === 'angry' ? (
            <>
              <path d="M72 86 Q83 79 94 85" stroke={INK} strokeWidth="4.5" strokeLinecap="round" fill="none" />
              <path d="M106 85 Q117 79 128 86" stroke={INK} strokeWidth="4.5" strokeLinecap="round" fill="none" />
            </>
          ) : (
            <>
              <path d="M74 87 Q84 82 94 87" stroke={INK} strokeWidth="3" strokeLinecap="round" fill="none" />
              <path d="M106 87 Q116 82 126 87" stroke={INK} strokeWidth="3" strokeLinecap="round" fill="none" />
            </>
          )}
        </motion.g>

        {/* ΓöÇΓöÇ MOUTH ΓöÇΓöÇ */}
        {mouthOpen ? (
          <ellipse cx="100" cy="126" rx="9" ry="7.5" fill={INK} />
        ) : state === 'correct' || state === 'hype' ? (
          <path d="M82 122 Q100 142 118 122 Z" fill={INK} />
        ) : state === 'wrong' || state === 'punishment' ? (
          <path d="M84 132 Q100 120 116 132" stroke={INK} strokeWidth="3.5" strokeLinecap="round" fill="none" />
        ) : state === 'angry' ? (
          <line x1="85" y1="127" x2="115" y2="127" stroke={INK} strokeWidth="3.5" strokeLinecap="round" />
        ) : state === 'thinking' ? (
          <circle cx="100" cy="126" r="5" stroke={INK} strokeWidth="3" fill="none" />
        ) : state === 'sad' ? (
          <path d="M90 134 Q100 126 110 134" stroke={INK} strokeWidth="2.5" strokeLinecap="round" fill="none" />
        ) : (
          <path d="M86 124 Q100 134 114 124" stroke={INK} strokeWidth="3.5" strokeLinecap="round" fill="none" />
        )}
        </motion.g>

      </svg>

      {/* Reaction glow burst */}
      {(state === 'correct' || state === 'hype') && (
        <motion.div
          className="absolute inset-0 rounded-full z-[-1] pointer-events-none"
          style={{ background: `radial-gradient(circle, ${palette?.glow || color + '80'} 0%, transparent 65%)` }}
          animate={{ scale: [1, 1.9], opacity: [0.85, 0] }}
          transition={{ duration: 0.7, repeat: state === 'hype' ? Infinity : 1 }}
        />
      )}
    </motion.div>
  )
}

'use client'

import { useState, useRef, useEffect, useCallback } from 'react'
import { motion } from 'framer-motion'

export interface CropSlot {
  key: 'topic_bg' | 'cat_setup' | 'cat_game'
  label: string
  sublabel: string
  width: number
  height: number
}

const SLOTS: CropSlot[] = [
  { key: 'topic_bg',  label: '╪«┘ä┘ü┘è╪⌐ ╪º┘ä┘à┘ê╪╢┘ê╪╣',        sublabel: '16:9 ΓÇö ╪╡┘ü╪¡╪⌐ ╪º┘ä╪Ñ╪╣╪»╪º╪»',  width: 320, height: 180 },
  { key: 'cat_setup', label: '╪¿╪╖╪º┘é╪⌐ ╪º┘ä┘ü╪ª╪⌐ (╪º┘ä╪Ñ╪╣╪»╪º╪»)', sublabel: '2:3 ΓÇö ╪º╪«╪¬┘è╪º╪▒ ╪º┘ä┘ü╪ª╪º╪¬',  width: 160, height: 240 },
  { key: 'cat_game',  label: '╪¿╪╖╪º┘é╪⌐ ╪º┘ä┘ü╪ª╪⌐ (╪º┘ä┘ä╪╣╪¿╪⌐)',  sublabel: '1:1 ΓÇö ╪┤╪¿┘â╪⌐ ╪º┘ä╪ú╪│╪ª┘ä╪⌐',  width: 220, height: 220 },
]

export interface CropConfig {
  topic_bg?:  { x: number; y: number; zoom: number }
  cat_setup?: { x: number; y: number; zoom: number }
  cat_game?:  { x: number; y: number; zoom: number }
}

interface Props {
  mediaUrl: string
  mediaType: 'image' | 'video'
  initialConfig?: CropConfig
  availableSlots?: Array<CropSlot['key']>
  onSave: (config: CropConfig) => void
  onClose: () => void
}

const DEFAULT_CROP = { x: 50, y: 50, zoom: 1 }

export default function MediaCropEditor({ mediaUrl, mediaType, initialConfig, availableSlots, onSave, onClose }: Props) {
  const [config, setConfig] = useState<CropConfig>(() => {
    const c: CropConfig = {}
    SLOTS.forEach(s => {
      if (!availableSlots || availableSlots.includes(s.key)) {
        c[s.key] = { ...(initialConfig?.[s.key] ?? DEFAULT_CROP) }
      }
    })
    return c
  })

  const dragRef = useRef<{
    key: CropSlot['key']
    slotW: number
    slotH: number
    startMouseX: number
    startMouseY: number
    startX: number
    startY: number
    zoom: number
  } | null>(null)

  const configRef = useRef(config)
  useEffect(() => { configRef.current = config }, [config])

  const startDrag = (key: CropSlot['key'], slotW: number, slotH: number, e: React.MouseEvent) => {
    e.preventDefault()
    const crop = configRef.current[key] ?? DEFAULT_CROP
    dragRef.current = {
      key, slotW, slotH,
      startMouseX: e.clientX,
      startMouseY: e.clientY,
      startX: crop.x,
      startY: crop.y,
      zoom: crop.zoom,
    }
  }

  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      const d = dragRef.current
      if (!d) return
      const dx = e.clientX - d.startMouseX
      const dy = e.clientY - d.startMouseY
      // Sensitivity: moving slotWidth pixels shifts 100% / zoom of the object-position range
      // Higher zoom = image is "bigger" relative to viewport = less position change per pixel
      const sensitivity = 100 / (d.slotW * d.zoom)
      const newX = Math.max(0, Math.min(100, d.startX - dx * sensitivity))
      const newY = Math.max(0, Math.min(100, d.startY - dy * sensitivity))
      setConfig(prev => ({ ...prev, [d.key]: { ...prev[d.key], x: newX, y: newY } }))
    }
    const onUp = () => { dragRef.current = null }
    window.addEventListener('mousemove', onMove)
    window.addEventListener('mouseup', onUp)
    return () => {
      window.removeEventListener('mousemove', onMove)
      window.removeEventListener('mouseup', onUp)
    }
  }, [])

  const setZoom = (key: CropSlot['key'], zoom: number) => {
    setConfig(prev => ({ ...prev, [key]: { ...(prev[key] ?? DEFAULT_CROP), zoom } }))
  }

  const resetSlot = (key: CropSlot['key']) => {
    setConfig(prev => ({ ...prev, [key]: { ...DEFAULT_CROP } }))
  }

  const visibleSlots = SLOTS.filter(s => !availableSlots || availableSlots.includes(s.key))

  return (
    <motion.div
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[200] flex items-center justify-center p-4"
      style={{ background: 'rgba(0,0,0,0.94)', backdropFilter: 'blur(24px)' }}
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <motion.div
        initial={{ scale: 0.9, y: 32 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9 }}
        className="bg-[#0c0c14] border border-white/10 rounded-3xl p-8 w-full max-w-5xl overflow-y-auto max-h-[95vh] space-y-8"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-start justify-between">
          <div>
            <h2 className="text-2xl font-black text-white">Γ£é∩╕Å ╪╢╪¿╪╖ ╪º┘ä┘ê╪│╪º╪ª╪╖</h2>
            <p className="text-white/40 text-sm mt-1">
              ┘â╪¿┘æ╪▒ ╪¿╪º┘ä╪│┘ä╪º┘è╪»╪▒ ╪½┘à ╪º╪│╪¡╪¿ ╪º┘ä╪Ñ╪╖╪º╪▒ ┘ä╪¬╪¡╪»┘è╪» ╪º┘ä┘à┘å╪╖┘é╪⌐ ╪º┘ä┘à╪▒╪ª┘è╪⌐
            </p>
          </div>
          <button onClick={onClose} className="text-white/30 hover:text-white text-2xl leading-none transition-colors">Γ£ò</button>
        </div>

        {/* Slot previews */}
        <div className="flex flex-wrap gap-10 justify-center">
          {visibleSlots.map(slot => {
            const crop = config[slot.key] ?? DEFAULT_CROP
            const { zoom, x, y } = crop

            // The media fills its box (object-fit cover), then we scale it and pin the origin
            const mediaStyle: React.CSSProperties = {
              display: 'block',
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              objectPosition: `${x}% ${y}%`,
              transform: `scale(${zoom})`,
              transformOrigin: `${x}% ${y}%`,
              pointerEvents: 'none',
              userSelect: 'none',
            }

            return (
              <div key={slot.key} className="flex flex-col items-center gap-4">
                {/* Labels */}
                <div className="text-center">
                  <p className="font-bold text-white text-sm">{slot.label}</p>
                  <p className="text-white/30 text-xs">{slot.sublabel}</p>
                </div>

                {/* Preview box */}
                <div
                  style={{
                    width: slot.width,
                    height: slot.height,
                    overflow: 'hidden',
                    position: 'relative',
                    flexShrink: 0,
                    borderRadius: 12,
                    border: `2px solid ${zoom > 1 ? 'rgba(168,85,247,0.6)' : 'rgba(255,255,255,0.15)'}`,
                    cursor: zoom > 1 ? 'grab' : 'default',
                    background: '#111',
                  }}
                  onMouseDown={e => zoom > 1 && startDrag(slot.key, slot.width, slot.height, e)}
                >
                  {mediaType === 'video' ? (
                    <video
                      key={mediaUrl}
                      src={mediaUrl}
                      autoPlay
                      loop
                      muted
                      playsInline
                      style={mediaStyle}
                    />
                  ) : (
                    <img
                      key={mediaUrl}
                      src={mediaUrl}
                      alt="preview"
                      draggable={false}
                      style={mediaStyle}
                    />
                  )}

                  {/* Crosshair */}
                  <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}>
                    <div style={{ position: 'absolute', left: '50%', top: 0, bottom: 0, width: 1, background: 'rgba(255,255,255,0.2)' }} />
                    <div style={{ position: 'absolute', top: '50%', left: 0, right: 0, height: 1, background: 'rgba(255,255,255,0.2)' }} />
                  </div>

                  {/* Hint when zoom=1 */}
                  {zoom <= 1 && (
                    <div style={{
                      position: 'absolute', inset: 0,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      background: 'rgba(0,0,0,0.3)',
                      pointerEvents: 'none',
                    }}>
                      <span style={{ color: 'rgba(255,255,255,0.5)', fontSize: 11, textAlign: 'center', padding: '0 8px' }}>
                        ┘â╪¿┘æ╪▒ ┘ä┘ä╪¬╪¡╪▒┘è┘â
                      </span>
                    </div>
                  )}
                </div>

                {/* Zoom slider */}
                <div style={{ width: slot.width }} className="flex flex-col gap-1">
                  <div className="flex justify-between text-xs text-white/40">
                    <span>╪¬┘â╪¿┘è╪▒</span>
                    <span className="font-mono">{zoom.toFixed(2)}├ù</span>
                  </div>
                  <input
                    type="range" min="1" max="3" step="0.05"
