                            <span className="text-xs font-semibold opacity-50">{team.score} ┘å┘é╪╖╪⌐</span>
                          </span>
                        </motion.button>
                      ))}
                    </div>

                    {/* No one button */}
                    <button onClick={() => finishQuestion(null)}
                      className="w-full py-3 rounded-2xl font-bold text-base transition-all hover:scale-[1.01] active:scale-[0.99]"
                      style={{
                        background: 'rgba(239,68,68,0.08)',
                        color: '#f87171',
                        border: '1px solid rgba(239,68,68,0.22)',
                      }}>
                      ┘ä╪º ╪ú╪¡╪» ╪ú╪¼╪º╪¿ Γ£ò
                    </button>
                  </div>
                ) : (
                  <motion.button
                    initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
