}

'use client'
import { useEffect, useState, useRef } from 'react'
import { motion } from 'framer-motion'

interface Props {
  initialSeconds: number
  isActive: boolean
  onTimeUp: () => void
  color?: string
}

export default function Timer({ initialSeconds, isActive, onTimeUp, color = '#8B5CF6' }: Props) {
  const [seconds, setSeconds] = useState(initialSeconds)

  const r = 45
  const circ = 2 * Math.PI * r
  const pct = seconds / initialSeconds
  const dash = circ * pct

  const timerColor = seconds > 10 ? color : seconds > 5 ? '#f59e0b' : '#ef4444'

  const hasFiredRef = useRef(false)

  useEffect(() => { 
    setSeconds(initialSeconds)
    hasFiredRef.current = false 
  }, [initialSeconds])

  useEffect(() => {
    if (!isActive || seconds < 0) return
    
    if (seconds === 0) {
      if (!hasFiredRef.current) {
        hasFiredRef.current = true
        onTimeUp()
      }
      return
    }

    const id = setInterval(() => setSeconds(p => p - 1), 1000)
    return () => clearInterval(id)
  }, [isActive, seconds, onTimeUp])

  return (
    <div className="relative flex items-center justify-center w-28 h-28">
      <svg className="w-full h-full" style={{ transform: 'rotate(-90deg)' }}>
        <circle cx="56" cy="56" r={r}
          stroke="rgba(255,255,255,0.08)" strokeWidth="6" fill="none" />
        <motion.circle cx="56" cy="56" r={r}
          stroke={timerColor} strokeWidth="6" fill="none"
          strokeLinecap="round"
          strokeDasharray={circ}
          animate={{ strokeDashoffset: circ - dash }}
          transition={{ duration: 0.9, ease: 'linear' }}
        />
      </svg>
      <div className="absolute flex flex-col items-center">
        <motion.span
          className="text-3xl font-black tabular-nums"
          animate={seconds <= 5 && isActive ? { scale: [1, 1.15, 1] } : {}}
          transition={{ repeat: Infinity, duration: 0.5 }}
          style={{ color: timerColor }}
        >
          {seconds}
        </motion.span>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence, Reorder } from 'framer-motion'

export interface Category {
  id: string
  name: string
  icon?: string
  topic_id?: string
  questionCount?: number
  video_url?: string
}

export interface Topic {
  id: string
  name: string
  icon?: string
  color?: string
  video_url?: string
  categories?: Category[]
}

interface TopicSelectorProps {
  topics: Topic[]
  setTopics: (topics: Topic[]) => void
  selectedCategories: string[]
  onToggleCategory: (id: string) => void
  maxSelections?: number
  searchQuery?: string
}

export default function TopicSelector({ topics, setTopics, selectedCategories, onToggleCategory, maxSelections = 6, searchQuery = '' }: TopicSelectorProps) {
  const [expandedTopics, setExpandedTopics] = useState<Record<string, boolean>>({})

  useEffect(() => {
    const initialExpanded: Record<string, boolean> = {}
    topics.forEach(t => { initialExpanded[t.id] = true })
    setExpandedTopics(initialExpanded)
  }, [topics])

  const toggleTopic = (id: string) => {
    setExpandedTopics(prev => ({ ...prev, [id]: !prev[id] }))
  }

  // Filter topics based on search query
  const filteredTopics = topics.filter(t => {
    if (!searchQuery) return true
    const matchTopic = t.name.toLowerCase().includes(searchQuery.toLowerCase())
    const matchCategory = t.categories?.some(c => c.name.toLowerCase().includes(searchQuery.toLowerCase()))
    return matchTopic || matchCategory
  })

  // We only reorder the displayed topics. To make it simple and safe, we can just let framer-motion reorder the filtered list.
  // But wait, reordering filtered lists can be tricky. Let's assume reorder is mainly used when search is empty.
  const handleReorder = (newOrder: Topic[]) => {
    if (searchQuery) return // Disable reorder while searching
    setTopics(newOrder)
  }

  return (
    <div className="space-y-6 w-full">
      <Reorder.Group axis="y" values={searchQuery ? filteredTopics : topics} onReorder={handleReorder} className="space-y-6">
        {filteredTopics.map((topic) => {
          const isExpanded = expandedTopics[topic.id]
          const categories = topic.categories || []
          const selectedInTopic = categories.filter(c => selectedCategories.includes(c.id)).length

          return (
            <Reorder.Item 
              key={topic.id} 
              value={topic}
              className="relative rounded-[2rem] overflow-hidden group cursor-grab active:cursor-grabbing"
              style={{
                background: 'rgba(255,255,255,0.02)',
                boxShadow: '0 8px 32px rgba(0,0,0,0.2)',
                border: '1px solid rgba(255,255,255,0.05)'
              }}
            >
              {/* Background Video */}
              {topic.video_url && (
                <div className="absolute inset-0 z-0">
                  <video 
                    src={topic.video_url} 
                    autoPlay 
                    loop 
                    muted 
                    playsInline 
                    className="w-full h-full object-cover opacity-60"
                  />
                  <div className="absolute inset-0 bg-black/50" />
                </div>
              )}

              {/* Content Container */}
              <div className="relative z-10">
                <div className="flex items-center justify-between p-6 bg-black/20 hover:bg-black/40 transition-colors">
                  <div className="flex items-center gap-6">
                    <div 
                      className="w-16 h-16 flex items-center justify-center text-3xl rounded-2xl shadow-2xl"
                      style={{ background: `${topic.color || '#5d24d6'}30`, border: `1px solid ${topic.color}50` }}
                    >
                      {topic.icon}
                    </div>
                    <div>
                      <h3 className="font-black text-2xl tracking-tight text-white">{topic.name}</h3>
                      <p className="font-mono text-xs uppercase tracking-widest mt-2 opacity-50">{categories.length} CATEGORIES</p>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    {selectedInTopic > 0 && (
                      <span className="font-mono text-xs tracking-widest px-4 py-2 rounded-full border border-white/10" style={{ color: topic.color || '#fff', backgroundColor: `${topic.color || '#5d24d6'}20` }}>
                        SELECTED: {selectedInTopic}
                      </span>
                    )}
                    
                    <button 
                      onPointerDown={(e) => e.stopPropagation()} // Prevent dragging when clicking the toggle
                      onClick={() => toggleTopic(topic.id)}
                      className="w-12 h-12 rounded-full border border-white/10 flex items-center justify-center bg-white/5 hover:bg-white/10 transition-colors"
                    >
                      <motion.div animate={{ rotate: isExpanded ? 180 : 0 }} transition={{ duration: 0.3 }}>
                        Γû╝
                      </motion.div>
                    </button>
                    
                    {/* Drag Handle Icon */}
                    <div className="w-8 h-8 flex flex-col items-center justify-center gap-1 opacity-20 hover:opacity-100 transition-opacity">
                      <div className="w-4 h-0.5 bg-white rounded-full" />
                      <div className="w-4 h-0.5 bg-white rounded-full" />
                      <div className="w-4 h-0.5 bg-white rounded-full" />
                    </div>
                  </div>
                </div>

                <AnimatePresence initial={false}>
                  {isExpanded && (
                    <motion.div
                      initial={{ height: 0, opacity: 0 }}
                      animate={{ height: 'auto', opacity: 1 }}
                      exit={{ height: 0, opacity: 0 }}
                      transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                      className="overflow-hidden"
                    >
                      <div className="p-6 pt-0 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4" onPointerDown={(e) => e.stopPropagation()}>
                        {categories.map(cat => {
                          const isSelected = selectedCategories.includes(cat.id)
                          const isMaxReached = selectedCategories.length >= maxSelections && !isSelected

                          return (
                            <motion.button
                              key={cat.id}
                              whileHover={!isMaxReached ? { scale: 1.03, y: -2 } : {}}
                              whileTap={!isMaxReached ? { scale: 0.97 } : {}}
                              onClick={() => onToggleCategory(cat.id)}
                              disabled={isMaxReached}
                              className={`relative p-5 rounded-2xl transition-all duration-300 flex flex-col justify-between min-h-[120px] overflow-hidden ${
                                isSelected 
                                  ? 'bg-white/10 border-2' 
                                  : isMaxReached
                                    ? 'bg-black/20 border border-white/5 opacity-40 cursor-not-allowed'
                                    : 'bg-black/30 border border-white/10 hover:bg-white/5'
                              }`}
                              style={isSelected ? { borderColor: topic.color || '#5d24d6', boxShadow: `0 0 30px ${topic.color || '#5d24d6'}40` } : {}}
                            >
                              {/* Subcategory Video */}
                              {cat.video_url && !isSelected && (
                                <video 
                                  src={cat.video_url} 
                                  autoPlay 
                                  loop 
                                  muted 
                                  playsInline 
                                  className="absolute inset-0 w-full h-full object-cover z-0 opacity-20"
                                />
                              )}

                              <div className="relative z-10 flex justify-between items-start w-full">
                                <span className="text-3xl drop-shadow-lg">{cat.icon || '≡ƒô¥'}</span>
                                {isSelected && (
                                  <motion.div 
                                    initial={{ scale: 0 }} animate={{ scale: 1 }} 
                                    className="w-3 h-3 rounded-full"
                                    style={{ backgroundColor: topic.color || '#fff', boxShadow: `0 0 10px ${topic.color || '#fff'}` }}
                                  />
                                )}
                              </div>
                              
                              <div className="relative z-10 w-full mt-4 text-right">
                                <span className="font-bold text-lg leading-tight text-white drop-shadow-md">{cat.name}</span>
                              </div>
                            </motion.button>
                          )
                        })}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </Reorder.Item>
          )
        })}
        {filteredTopics.length === 0 && (
          <div className="py-20 text-center text-white/40 font-mono text-sm tracking-widest">
            NO TOPICS FOUND
          </div>
        )}
      </Reorder.Group>
    </div>
  )
}

const fs = require('fs');
const path = require('path');

function walk(dir) {
  let results = [];
  const list = fs.readdirSync(dir);
  list.forEach(function(file) {
    file = path.join(dir, file);
    const stat = fs.statSync(file);
    if (stat && stat.isDirectory()) { 
      results = results.concat(walk(file));
    } else { 
      if(file.endsWith('.ts') || file.endsWith('.tsx')) {
        results.push(file);
      }
    }
  });
  return results;
}

const dirs = ['app', 'components', 'lib', 'hooks', 'store'];
let files = [];
dirs.forEach(d => {
  if(fs.existsSync(d)) files = files.concat(walk(d));
});

let report = '# SyntaxError Investigation\n\n';
let foundAny = false;

files.forEach(f => {
  const content = fs.readFileSync(f, 'utf8');
  const lines = content.split('\n');
  lines.forEach((l, i) => {
    // Check for invisible chars: Zero-width space, non-breaking space, etc
    const matches = l.match(/[\u200B-\u200D\uFEFF]/g);
    if(matches) {
      report += `- **File:** ${f}\n`;
      report += `- **Line ${i+1}:** Contains zero-width or invisible characters: ${matches.map(c => '\\u' + c.charCodeAt(0).toString(16).padStart(4, '0')).join(', ')}\n\n`;
      foundAny = true;
    }
  });
});

if(!foundAny) {
  report += 'No zero-width characters found in any source files.\n\n';

  // Let's also run next build to capture the raw error and put it in the report
  const { execSync } = require('child_process');
  try {
    report += '## Next.js Build Output\n\n';
    const output = execSync('npx next build', { encoding: 'utf8', stdio: 'pipe' });
    report += '```\n' + output + '\n```\n';
  } catch(e) {
    report += '```\n' + e.stdout + '\n' + e.stderr + '\n```\n';
  }
}

fs.writeFileSync('XX.md', report);
console.log('Done! Wrote results to XX.md');

'use client'

import { useEffect, useState, useCallback } from 'react'
import { createClient } from '@/lib/supabaseClient'
import { useGameStore } from '@/store/gameStore'
import type { MascotState } from '@/types/game'
import { audioDirector, SequenceStep } from '@/lib/audioDirector'

interface MascotPhrase {
  id: string
  category: string
  text: string
  audio_url?: string
}

interface MascotSettings {
  enabled: boolean
  sarcasm_level: number
  energy_level: number
  voice_enabled: boolean
  voice_id?: string
  active_mascot_id?: string
}

export function useMascotBehavior() {
  const supabase = createClient()
  const [phrases, setPhrases] = useState<MascotPhrase[]>([])
  const [settings, setSettings] = useState<MascotSettings | null>(null)
  const store = useGameStore()

  useEffect(() => {
    async function loadMascotData() {
      const [settsRes, phrsRes] = await Promise.all([
        (supabase.from('mascot_settings') as any).select('*').single(),
        (supabase.from('mascot_phrases') as any).select('*').eq('is_active', true),
      ])
      if (settsRes.data) {
        setSettings(settsRes.data)
        // Sync configuration snapshot to Audio Director
        if (settsRes.data.timing_config) {
          audioDirector.updateConfig(settsRes.data.timing_config)
        }
      }
      if (phrsRes.data) setPhrases(phrsRes.data)
    }
    loadMascotData()
  }, [])

  const triggerReaction = useCallback((type: 'correct' | 'wrong' | 'hype' | 'punishment' | 'thinking' | 'intro', overrideText?: string) => {
    if (!settings?.enabled || type === 'punishment') return

    let state: MascotState = 'idle'
    if (type === 'correct') state = 'correct'
    if (type === 'wrong') state = 'wrong'
    if (type === 'hype') state = 'hype'
    if (type === 'thinking') state = 'thinking'

    // Determine the text/audio
    let selectedPhrase: MascotPhrase | null = null
    let textToSpeak = overrideText

    if (!textToSpeak) {
      const categoryPhrases = phrases.filter(p => p.category === type)
      if (categoryPhrases.length > 0) {
        selectedPhrase = categoryPhrases[Math.floor(Math.random() * categoryPhrases.length)]
        textToSpeak = selectedPhrase.text
      }
    }

    // Helper to clamp delays securely
    const clampDelay = (val: any, min: number, max: number, def: number) => {
      if (typeof val !== 'number') return def
      return Math.min(Math.max(val, min), Math.min(max, 1200)) // Max global pacing rule
    }

    const timing = (settings as any)?.timing_config || {}
    const delayCorrect = clampDelay(timing.correct, 150, 700, 350)
    const delayWrong = clampDelay(timing.wrong, 100, 600, 250)
    const delayReveal = clampDelay(timing.reveal, 200, 900, 400)

    // Build the Sequence
    const sequence: SequenceStep[] = []

    // 1. Prepend SFX and TV Show micro-delay (Safely Clamped)
    if (type === 'correct' || type === 'hype') {
      sequence.push({ kind: 'sfx', type: 'correct' })
      sequence.push({ kind: 'wait', durationMs: delayCorrect })
    } else if (type === 'wrong') {
      sequence.push({ kind: 'sfx', type: 'wrong' })
      sequence.push({ kind: 'wait', durationMs: delayWrong })
    } else if (type === 'thinking') {
      sequence.push({ kind: 'sfx', type: 'reveal' })
      sequence.push({ kind: 'wait', durationMs: delayReveal })
    } else if (type === 'intro') {
      sequence.push({ kind: 'sfx', type: 'intro' })
      sequence.push({ kind: 'wait', durationMs: 200 })
    }

    // 2. Set State immediately
    if (state !== 'idle') {
      sequence.push({ kind: 'hook', fn: () => store.setMascotState(state) })
    }

    // 3. Play Audio/TTS if available
    if (selectedPhrase?.audio_url) {
      sequence.push({ kind: 'hook', fn: () => store.setIsTalking(true) })
      sequence.push({ kind: 'mp3', url: selectedPhrase.audio_url })
      sequence.push({ kind: 'hook', fn: () => store.setIsTalking(false) })
    } else if (textToSpeak && settings.voice_enabled) {
      const pitch = 1.0 + (settings.energy_level - 50) * 0.01
      const rate = 1.0 + (settings.energy_level - 50) * 0.005
      sequence.push({ kind: 'tts', text: textToSpeak, pitch, rate })
    }

    // 4. Revert to Idle state after sequence
    sequence.push({ kind: 'wait', durationMs: 1500 })
    sequence.push({ kind: 'hook', fn: () => store.setMascotState('idle') })

    // Determine priority
    const priorityMap: Record<string, 'interrupt'|'high'|'normal'|'low'> = {
      correct: 'interrupt',
      wrong: 'interrupt',
      hype: 'high',
      punishment: 'high',
      thinking: 'normal',
      intro: 'normal'
    }

    // Push to engine
    audioDirector.runSequence(sequence, { 
      priority: priorityMap[type] || 'normal',
      atomicMode: 'cancel' // If interrupted, stop talking
    })

    return textToSpeak || ""
  }, [settings, phrases, store])

  return {
    triggerReaction,
    settings,
    phrases,
  }
}

'use client'

import { useState, useMemo } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabaseClient'
import { gameEngine } from '@/lib/gameEngine'
import { useGameStore } from '@/store/gameStore'
import { GameMode } from '@/types/game'
import toast from 'react-hot-toast'

export function useSession() {
  const router = useRouter()
  const supabase = useMemo(() => createClient(), [])
  const [isCreating, setIsCreating] = useState(false)
  const setSession = useGameStore((state) => state.setSession)

  /**
   * Initialize a new game session.
   */
  const createSession = async (mode: GameMode) => {
    setIsCreating(true)
    try {
      let { data: { user } } = await supabase.auth.getUser()

      // If no user, sign in anonymously ΓÇö creates a real UUID in auth.users
      if (!user) {
        const { data, error } = await supabase.auth.signInAnonymously()
        if (error) throw error
        user = data.user
      }

      const isGuest = user?.app_metadata?.provider === 'anonymous'
      const hostId = user!.id  // now a real UUID, always

      let profile: any = null
      if (!isGuest && user) {
        const { data: p } = await (supabase
          .from('profiles') as any)
          .select('free_sessions_used')
          .eq('id', user.id)
          .single()
        profile = p
      }


      // Create session via engine
      const session = await gameEngine.createSession(hostId, mode)
      
      // Update store
      setSession(session.id, mode)

      // Mark free session as used for authenticated users
      if (!isGuest && profile && !profile.free_sessions_used && user) {
        await (supabase
          .from('profiles') as any)
          .update({ free_sessions_used: true })
          .eq('id', user.id)
      }

      toast.success('╪¬┘à ╪Ñ┘å╪┤╪º╪í ╪º┘ä╪¼┘ä╪│╪⌐ ╪¿┘å╪¼╪º╪¡')
      router.push(`/game/setup/${session.id}`)
      return session
    } catch (error: any) {
      toast.error('┘ü╪┤┘ä ╪Ñ┘å╪┤╪º╪í ╪º┘ä╪¼┘ä╪│╪⌐: ' + error.message)
      return null
    } finally {
      setIsCreating(false)
    }
  }

  const selectCategories = async (sessionId: string, categoryIds: string[]) => {
    try {
      await gameEngine.selectCategories(sessionId, categoryIds)
    } catch (error: any) {
      toast.error('╪«╪╖╪ú ┘ü┘è ╪¡┘ü╪╕ ╪º┘ä┘ü╪ª╪º╪¬: ' + error.message)
      throw error
    }
  }

  const generateQuestions = async (sessionId: string) => {
    try {
      await gameEngine.generateQuestions(sessionId)
    } catch (error: any) {
      toast.error('╪«╪╖╪ú ┘ü┘è ╪¬┘ê┘ä┘è╪» ╪º┘ä╪ú╪│╪ª┘ä╪⌐: ' + error.message)
      throw error
    }
  }

  return {
    isCreating,
    createSession,
    selectCategories,
    generateQuestions
  }
}

