export default function AdminCategoriesPage() {
  const supabase = createClient()
  const [cats, setCats] = useState<CategoryWithQuestions[]>([])
  const [topics, setTopics] = useState<AdminCategory[]>([])
  const [loading, setLoading] = useState(true)
  const [modal, setModal] = useState(false)
  const [editing, setEditing] = useState<CategoryWithQuestions | null>(null)
  const [form, setForm] = useState({ id: '', name: '', icon: '≡ƒôÜ', topic_id: '', image_url: '', hide_icon: false })
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [deleteId, setDeleteId] = useState<string | null>(null)
  const [cropEditorUrl, setCropEditorUrl] = useState<string | null>(null)
  const [cropConfig, setCropConfig] = useState<CropConfig | null>(null)

  async function load() {
    const [catsRes, topicsRes] = await Promise.all([
      supabase.from('categories').select('*, topics(name, color), questions(count)').order('name'),
      supabase.from('topics').select('id, name').order('order_index')
    ])
    
    setCats(catsRes.data ?? [])
    setTopics(topicsRes.data ?? [])
    setLoading(false)
  }
  useEffect(() => { load() }, [])

  function openAdd() { 
    setForm({ id: `cat-${Date.now()}`, name: '', icon: '≡ƒôÜ', topic_id: topics[0]?.id || '', image_url: '', hide_icon: false })
    setEditing(null)
    setModal(true) 
  }
  function openEdit(c: CategoryWithQuestions) { 
    setForm({ id: c.id, name: c.name, icon: c.icon ?? '≡ƒôÜ', topic_id: c.topic_id || '', image_url: c.image_url || '', hide_icon: c.hide_icon || false })
    setCropConfig(c.crop_config || null)
    setEditing(c)
    setModal(true) 
  }

  async function handleImageUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return

    setUploading(true)
    const fileExt = file.name.split('.').pop()
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`
    const filePath = `category_backgrounds/${fileName}`

    try {
      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file)

      if (uploadError) throw uploadError

      const { data } = supabase.storage
        .from('images')
        .getPublicUrl(filePath)

      setForm(f => ({ ...f, image_url: data.publicUrl }))
      setCropEditorUrl(data.publicUrl)  // Auto-open crop editor after upload
      toast.success('╪¬┘à ╪▒┘ü╪╣ ╪º┘ä╪╡┘ê╪▒╪⌐ ╪¿┘å╪¼╪º╪¡! ╪º╪╢╪¿╪╖ ╪º┘ä┘é╪╡ ╪º┘ä╪ó┘å.')
    } catch (error: any) {
      toast.error('╪«╪╖╪ú ┘ü┘è ╪º┘ä╪▒┘ü╪╣: ' + error.message)
    } finally {
      setUploading(false)
    }
  }

  async function save() {
    if (!form.name.trim()) { toast.error('╪º╪│┘à ╪º┘ä┘ü╪ª╪⌐ ┘à╪╖┘ä┘ê╪¿'); return }
    setSaving(true)
    const payload = { 
      id: form.id,
      name: form.name.trim(), 
      icon: form.icon, 
      topic_id: form.topic_id || null, 
      image_url: form.image_url, 
      hide_icon: form.hide_icon,
      crop_config: cropConfig || null
    }
    const { error } = editing
      ? await supabase.from('categories').update(payload).eq('id', editing.id)
      : await supabase.from('categories').insert(payload)
    if (error) { toast.error(error.message); setSaving(false); return }
    toast.success(editing ? '╪¬┘à ╪º┘ä╪¬╪¡╪»┘è╪½' : '╪¬┘à╪¬ ╪º┘ä╪Ñ╪╢╪º┘ü╪⌐')
    setModal(false); setSaving(false); load()
  }

  async function del(id: string) {
    const { error } = await supabase.from('categories').delete().eq('id', id)
    if (error) { toast.error(error.message); return }
    toast.success('╪¬┘à ╪º┘ä╪¡╪░┘ü'); setDeleteId(null); load()
  }

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-black gradient-text-primary">╪º┘ä┘ü╪ª╪º╪¬</h1>
