  }, [])

  const handleGenerate = async (cat: GeneratorCategory) => {
    setGeneratingId(cat.id)
    try {
      const res = await fetch('/api/admin/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
