'use client'

import { useEffect, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { createClient } from '@/lib/supabaseClient'
import toast from 'react-hot-toast'
import { QuestionWithCategory, AdminCategory } from '@/types/admin'

const DIFFICULTIES = ['easy', 'medium', 'hard'] as const
const DIFF_LABELS: Record<string, string> = { easy: '╪│┘ç┘ä', medium: '┘à╪¬┘ê╪│╪╖', hard: '╪╡╪╣╪¿' }

export default function AdminQuestionsPage() {
  const supabase = createClient()
  const [questions, setQuestions] = useState<QuestionWithCategory[]>([])
  const [categories, setCategories] = useState<AdminCategory[]>([])
  const [loading, setLoading] = useState(true)
  const [modal, setModal] = useState(false)
  const [editing, setEditing] = useState<QuestionWithCategory | null>(null)
  const [form, setForm] = useState({ category_id: '', difficulty: 'easy' as 'easy'|'medium'|'hard', question: '', answer: '', media_url: '' })
  const [saving, setSaving] = useState(false)
  const [search, setSearch] = useState('')
  const [filterDiff, setFilterDiff] = useState('')
  const [deleteId, setDeleteId] = useState<string | null>(null)

  async function load() {
    const [q, c] = await Promise.all([
      supabase.from('questions').select('*, categories(name)').order('created_at', { ascending: false }),
      supabase.from('categories').select('*').order('name'),
    ])
    setQuestions(q.data ?? [])
    setCategories(c.data ?? [])
    setLoading(false)
  }
  useEffect(() => { load() }, [])

  function openAdd() {
    setForm({ category_id: '', difficulty: 'easy', question: '', answer: '', media_url: '' })
    setEditing(null); setModal(true)
  }
  function openEdit(q: QuestionWithCategory) {
    setForm({ category_id: q.category_id ?? '', difficulty: q.difficulty, question: q.question, answer: q.answer, media_url: q.media_url ?? '' })
    setEditing(q); setModal(true)
  }

  async function save() {
    if (!form.question.trim() || !form.answer.trim()) { toast.error('╪º┘ä╪│╪ñ╪º┘ä ┘ê╪º┘ä╪Ñ╪¼╪º╪¿╪⌐ ┘à╪╖┘ä┘ê╪¿╪º┘å'); return }
    setSaving(true)
    const payload = { category_id: form.category_id || null, difficulty: form.difficulty, question: form.question.trim(), answer: form.answer.trim(), media_url: form.media_url.trim() || null }
    const { error } = editing
      ? await supabase.from('questions').update(payload).eq('id', editing.id)
      : await supabase.from('questions').insert(payload)
    if (error) { toast.error(error.message); setSaving(false); return }
    toast.success(editing ? '╪¬┘à ╪º┘ä╪¬╪¡╪»┘è╪½' : '╪¬┘à╪¬ ╪º┘ä╪Ñ╪╢╪º┘ü╪⌐')
    setModal(false); setSaving(false); load()
  }

  async function del(id: string) {
    const { error } = await supabase.from('questions').delete().eq('id', id)
    if (error) { toast.error(error.message); return }
    toast.success('╪¬┘à ╪º┘ä╪¡╪░┘ü'); setDeleteId(null); load()
  }

  const filtered = questions.filter(q =>
    (!search || q.question.includes(search) || q.answer.includes(search)) &&
    (!filterDiff || q.difficulty === filterDiff)
