                      <button onClick={() => setDeleteId(q.id)} className="btn btn-sm" style={{ padding: '4px 12px', background: 'rgba(239,68,68,0.1)', color: '#ef4444', border: '1px solid rgba(239,68,68,0.2)' }}>╪¡╪░┘ü</button>
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && <tr><td colSpan={5} className="px-4 py-10 text-center" style={{ color: 'var(--color-text-muted)' }}>┘ä╪º ╪¬┘ê╪¼╪» ┘å╪¬╪º╪ª╪¼</td></tr>}
            </tbody>
          </table>
        </div>
      )}

      {/* Add/Edit Modal */}
      <AnimatePresence>
        {modal && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
