                <input className="input" value={form.answer} onChange={e => setForm(f => ({ ...f, answer: e.target.value }))} placeholder="╪º┘ä╪Ñ╪¼╪º╪¿╪⌐ ╪º┘ä╪╡╪¡┘è╪¡╪⌐" />
              </div>
              <div>
                <label className="label">╪▒╪º╪¿╪╖ ╪╡┘ê╪▒╪⌐ (╪º╪«╪¬┘è╪º╪▒┘è)</label>
