                <button onClick={save} disabled={saving} className="btn btn-primary flex-1">{saving ? '╪¼╪º╪▒┘è ╪º┘ä╪¡┘ü╪╕...' : editing ? '╪¡┘ü╪╕ ╪º┘ä╪¬╪╣╪»┘è┘ä╪º╪¬' : '╪Ñ╪╢╪º┘ü╪⌐'}</button>
                <button onClick={() => setModal(false)} className="btn btn-ghost">╪Ñ┘ä╪║╪º╪í</button>
