    setLoading(true)
    try {
      const [topicsRes, catsRes] = await Promise.all([
        supabase.from('topics').select('*').order('order_index'),
        supabase.from('categories').select('*'),
      ])

      let rawTopics: any[] = topicsRes.data ?? []
      let rawCats:   any[] = catsRes.data   ?? []

      // Use fallback if DB is empty
      if (rawTopics.length === 0) {
        rawTopics = FALLBACK_TOPICS
        rawCats   = FALLBACK_CATS
      }

      const merged = rawTopics.map(topic => ({
        ...topic,
        categories: rawCats.filter(c => c.topic_id === topic.id),
      }))

      setTopics(merged)
    } catch (err: any) {
      toast.error(err?.message ?? 'Failed to load topics')
    } finally {
      setLoading(false)
    }
  }

