import { NextResponse } from 'next/server'
import { createClient, createAdminClient } from '@/lib/supabaseServer'
import { generateSession } from '@/lib/gemini'

interface GenerateRequest {
  sessionId: string
  teams: number
  categories: string[]
}

interface ResolvedCategory {
  id: string
  name: string
  topics: {
    name: string
  } | null
}

export async function POST(req: Request) {
  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

    const { data: profile } = await supabase.from('profiles').select('role').eq('id', user.id).single()
    const userRole = profile?.role
    if (userRole !== 'admin') return NextResponse.json({ error: 'Forbidden' }, { status: 403 })

    const { sessionId, teams, categories: categoryIds } = await req.json() as GenerateRequest

    if (!sessionId || !teams || !categoryIds) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }

    const supabaseAdmin = createAdminClient()

    const { data: resolvedCats, error: resolveError } = await supabaseAdmin
      .from('categories')
      .select('id, name, topics(name)')
      .in('id', categoryIds) as { data: ResolvedCategory[] | null, error: any }

    if (resolveError || !resolvedCats) {
      throw new Error('Failed to resolve categories')
    }

    const categoriesForAI = categoryIds.map(id => {
      const cat = resolvedCats.find(c => c.id === id)
      return {
        name: cat?.name || 'General',
        topicName: cat?.topics?.name || 'General'
      }
    })

    const questions = await generateSession({ 
      sessionId, 
      teams: teams as 2 | 3 | 4, 
      categories: categoriesForAI 
    })

    const { error: upsertError } = await supabaseAdmin
      .from('questions')
      .upsert(
        questions.map(q => ({
          category_id: q.category_id,
          difficulty: q.difficulty,
          question: q.question,
          answer: q.answer
        })),
        { onConflict: 'question', ignoreDuplicates: true }
      )

    if (upsertError) throw upsertError

    return NextResponse.json({ success: true, count: questions.length })

  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { createClient } from '@/lib/supabaseServer'
import { NextResponse, type NextRequest } from 'next/server'

export const dynamic = 'force-dynamic'

/**
 * POST /api/game/submit-answer
 *
 * Server-Authoritative scoring endpoint.
 * The CLIENT only sends: { sessionQuestionId, teamId }
 * The SERVER validates the question, calculates points from the DB scoring config,
 * and atomically updates the score. The client cannot manipulate points.
 */
export async function POST(request: NextRequest) {
  // 1. Authenticate the user ΓÇö reject anonymous requests
  const supabase = await createClient()
  const { data: { user }, error: authError } = await supabase.auth.getUser()

  if (authError || !user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  // 2. Parse body ΓÇö only trust minimal inputs
  let body: { sessionQuestionId?: string; teamId?: string }
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 })
  }

  const { sessionQuestionId, teamId } = body

  if (!sessionQuestionId || !teamId) {
    return NextResponse.json({ error: 'Missing sessionQuestionId or teamId' }, { status: 400 })
  }

  // 3. Fetch the session question ΓÇö server-side validation
  const { data: sq, error: sqError } = await (supabase
    .from('session_questions') as any)
    .select('id, used, difficulty, session_id, question_id')
    .eq('id', sessionQuestionId)
    .single()

  if (sqError || !sq) {
    return NextResponse.json({ error: 'Question not found' }, { status: 404 })
  }

  // 4. Guard: prevent duplicate scoring (idempotency)
  if (sq.used) {
    return NextResponse.json({ error: 'Question already answered', alreadyUsed: true }, { status: 409 })
  }

  // 5. Validate the team belongs to the same session
  const { data: team, error: teamError } = await (supabase
    .from('teams') as any)
    .select('id, session_id, score')
    .eq('id', teamId)
    .single()

  if (teamError || !team) {
    return NextResponse.json({ error: 'Team not found' }, { status: 404 })
  }

  if (team.session_id !== sq.session_id) {
    return NextResponse.json({ error: 'Team does not belong to this session' }, { status: 403 })
  }

  // 6. Validate the user is the host of this session
  const { data: session, error: sessionError } = await (supabase
    .from('sessions') as any)
    .select('host_id, current_team_index, state')
    .eq('id', sq.session_id)
    .single()

  if (sessionError || !session) {
    return NextResponse.json({ error: 'Session not found' }, { status: 404 })
  }

  if (session.host_id !== user.id) {
    return NextResponse.json({ error: 'Only the host can submit answers' }, { status: 403 })
  }

  if (session.state !== 'playing') {
    return NextResponse.json({ error: 'Game is not in playing state' }, { status: 400 })
  }

  // 7. Fetch scoring config from DB ΓÇö server decides the points
  const { data: scoringConfig } = await (supabase
    .from('scoring_config') as any)
    .select('easy_points, medium_points, hard_points')
    .limit(1)
    .single()

  const config = scoringConfig ?? { easy_points: 100, medium_points: 200, hard_points: 300 }

  const pointsMap: Record<string, number> = {
    easy:   config.easy_points,
    medium: config.medium_points,
    hard:   config.hard_points,
  }
  const pointsToAward = pointsMap[sq.difficulty] ?? 100

  // 8. Atomic operations: mark used + award points + advance turn
  const totalTeams = await (supabase
    .from('teams') as any)
    .select('id', { count: 'exact', head: true })
    .eq('session_id', sq.session_id)

  const teamCount = totalTeams.count ?? 2
  const nextTeamIndex = (session.current_team_index + 1) % teamCount

  // Run all three DB mutations in parallel
  const [markResult, scoreResult, turnResult] = await Promise.all([
    // Mark question as used
    (supabase
      .from('session_questions') as any)
      .update({ used: true })
      .eq('id', sessionQuestionId),

    // Atomically increment score using server-side RPC
    (supabase.rpc as any)('increment_team_score', {
      team_id:       teamId,
      points_to_add: pointsToAward,
    }),

    // Advance turn
    (supabase
      .from('sessions') as any)
      .update({ current_team_index: nextTeamIndex })
      .eq('id', sq.session_id),
  ])

  if (markResult.error)  console.error('[submit-answer] mark used error:', markResult.error)
  if (scoreResult.error) console.error('[submit-answer] score RPC error:',  scoreResult.error)
  if (turnResult.error)  console.error('[submit-answer] turn update error:', turnResult.error)

  // 9. Return the authoritative result to the client
  return NextResponse.json({
    success:       true,
    pointsAwarded: pointsToAward,
    nextTeamIndex,
    teamId,
  })
}

import { NextResponse } from 'next/server'
import { generateNewQuestions } from '@/lib/aiService'
import { createClient } from '@supabase/supabase-js'

const supabaseAdmin = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

export async function POST(req: Request) {
  try {
    const { categoryId, categoryName, difficulty, count, exclude } = await req.json()

    if (!categoryId || !categoryName || !difficulty) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 })
    }

    console.log(`Generating ${count} ${difficulty} questions for ${categoryName} (excluding ${exclude?.length || 0})...`)
    
    const newQuestions = await generateNewQuestions(categoryName, difficulty, count || 3, exclude || [])

    if (newQuestions.length === 0) {
      return NextResponse.json({ error: 'Failed to generate questions' }, { status: 500 })
    }

    // Insert into DB for future use
    const inserts = newQuestions.map((q: any) => ({
      category_id: categoryId,
      difficulty: q.difficulty || difficulty, // Use AI's difficulty or fallback
      question: q.question,
      answer: q.answer
    }))

    const { data, error } = await supabaseAdmin
      .from('questions')
      .upsert(inserts, { onConflict: 'category_id, question' })
      .select()

    if (error) {
      console.error('DB Upsert Error:', error)
      return NextResponse.json({ error: 'Failed to save questions to DB' }, { status: 500 })
    }

    return NextResponse.json({ questions: data })
  } catch (error: any) {
    console.error('API Route Error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

import { createClient } from '@/lib/supabaseServer'
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'
import { sendProConfirmationEmail } from '@/lib/email'

export const dynamic = 'force-dynamic'

// ΓöÇΓöÇ Paddle Webhook Handler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Receives events from Paddle and updates the user's plan in Supabase
// Set the webhook URL in Paddle Dashboard ΓåÆ Notifications ΓåÆ Add Endpoint:
//   https://abu-al-areef-trivia-main.vercel.app/api/webhooks/paddle

// Paddle sends a signature header ΓÇö we verify it to prevent spoofing.
const PADDLE_WEBHOOK_SECRET = process.env.PADDLE_WEBHOOK_SECRET ?? ''

async function verifyPaddleSignature(request: NextRequest, rawBody: string): Promise<boolean> {
  // If no secret configured (dev mode), skip verification
  if (!PADDLE_WEBHOOK_SECRET) {
    console.warn('[Paddle] No webhook secret set ΓÇö skipping signature verification')
    return true
  }

  const signatureHeader = request.headers.get('paddle-signature')
  if (!signatureHeader) return false

  // Parse ts= and h1= from the header
  const parts = Object.fromEntries(
    signatureHeader.split(';').map(p => p.split('=') as [string, string])
  )
  const ts = parts['ts']
  const h1 = parts['h1']
  if (!ts || !h1) return false

  // HMAC-SHA256 verification
  const encoder = new TextEncoder()
  const key = await crypto.subtle.importKey(
    'raw', encoder.encode(PADDLE_WEBHOOK_SECRET),
    { name: 'HMAC', hash: 'SHA-256' }, false, ['verify']
  )
  const payload = `${ts}:${rawBody}`
  const signatureBytes = Uint8Array.from(Buffer.from(h1, 'hex'))
  const isValid = await crypto.subtle.verify('HMAC', key, signatureBytes, encoder.encode(payload))
  return isValid
}

export async function POST(request: NextRequest) {
  const rawBody = await request.text()

  // ΓöÇΓöÇ Signature Verification ΓöÇΓöÇ
  const isValid = await verifyPaddleSignature(request, rawBody)
  if (!isValid) {
    console.error('[Paddle] Invalid webhook signature')
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  let event: Record<string, unknown>
  try {
    event = JSON.parse(rawBody)
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 })
  }

  const eventType = event.event_type as string
  const data = event.data as Record<string, unknown>

  console.log(`[Paddle] Received event: ${eventType}`)

  const supabase = await createClient()

  // ΓöÇΓöÇ Handle Subscription Events ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (eventType === 'subscription.created' || eventType === 'subscription.updated') {
    const customData = data.custom_data as Record<string, string> | null
    const userId = customData?.user_id

    if (!userId) {
      console.error('[Paddle] No user_id in custom_data')
      return NextResponse.json({ error: 'Missing user_id' }, { status: 400 })
    }

    const subscriptionId   = data.id as string
    const status           = data.status as string          // active | canceled | past_due
    const priceId          = (data.items as Array<Record<string, unknown>>)?.[0]?.price_id as string
    const periodEnd        = (data.current_billing_period as Record<string, string>)?.ends_at

    // Map price_id ΓåÆ plan_type
    const proPriceId  = process.env.NEXT_PUBLIC_PADDLE_PRICE_PRO  ?? ''
    const teamPriceId = process.env.NEXT_PUBLIC_PADDLE_PRICE_TEAM ?? ''
    const planType = priceId === teamPriceId ? 'team' : priceId === proPriceId ? 'pro' : 'free'

    // Upsert into subscriptions table
    const { error: subError } = await supabase
      .from('subscriptions')
      .upsert({
        user_id:                userId,
        paddle_subscription_id: subscriptionId,
        status,
        plan_type:              planType,
        current_period_end:     periodEnd ?? null,
      }, { onConflict: 'user_id' })

    if (subError) {
      console.error('[Paddle] Subscription upsert error:', subError)
      return NextResponse.json({ error: 'DB error' }, { status: 500 })
    }

    // Also update the plan_type on the profiles table for fast reads
    await supabase
      .from('profiles')
      .update({ plan_type: status === 'active' ? planType : 'free' })
      .eq('id', userId)

    console.log(`[Paddle] Updated user ${userId} to plan: ${planType} (${status})`)

    // Send Pro Confirmation email on activation
    if (status === 'active' && planType !== 'free') {
      const { data: profile } = await supabase.from('profiles').select('email').eq('id', userId).single()
      if (profile?.email) {
        await sendProConfirmationEmail({
          to:   profile.email,
          name: profile.email,
          plan: planType as 'pro' | 'team',
        }).catch(err => console.error('[Email] Pro confirmation failed:', err))
      }
    }
  }

  // ΓöÇΓöÇ Handle Subscription Cancelled ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (eventType === 'subscription.canceled') {
    const customData = data.custom_data as Record<string, string> | null
    const userId = customData?.user_id

    if (userId) {
      await supabase.from('profiles').update({ plan_type: 'free' }).eq('id', userId)
      await supabase
        .from('subscriptions')
        .update({ status: 'canceled' })
        .eq('user_id', userId)

      console.log(`[Paddle] Downgraded user ${userId} to free (canceled)`)
    }
  }

  // ΓöÇΓöÇ Record Payment & Credits ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (eventType === 'transaction.completed') {
    const customData = data.custom_data as Record<string, any> | null
    const userId = customData?.user_id
    const sessionsToAdd = Number(customData?.sessions || 0)
    const totals = (data.details as any)?.totals

    if (userId) {
      // 1. Record the payment
      await supabase.from('payments').insert({
        user_id:               userId,
        type:                  sessionsToAdd > 0 ? 'session' : 'subscription',
        status:                'completed',
        paddle_transaction_id: data.id as string,
        amount:                Number(totals?.total ?? 0) / 100,
        currency:              data.currency_code as string,
      })

      // 2. If it's a session pack, increment credits
      if (sessionsToAdd > 0) {
        // We use an RPC or a manual increment
        // Assuming profiles has a session_credits column (verified in database.ts)
        const { data: profile } = await supabase
          .from('profiles')
          .select('session_credits')
          .eq('id', userId)
          .single()

        const currentCredits = profile?.session_credits || 0
        await supabase
          .from('profiles')
          .update({ session_credits: currentCredits + sessionsToAdd })
          .eq('id', userId)

        console.log(`[Paddle] Added ${sessionsToAdd} credits to user ${userId}. New total: ${currentCredits + sessionsToAdd}`)
      }
    }
  }

  return NextResponse.json({ received: true }, { status: 200 })
}

