            transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
            className="w-full rounded-full flex-shrink-0"
          />
          {s === current && (
             <motion.div 
               layoutId="progress-glow"
               className="absolute inset-0 blur-[4px] rounded-full"
               style={{ background: accentColor, opacity: 0.3 }}
