      const emailDomain = email.split('@')[1]
      if (!email || !email.includes('@')) {
        e.email = '╪¿╪▒┘è╪» ╪Ñ┘ä┘â╪¬╪▒┘ê┘å┘è ╪║┘è╪▒ ╪╡╪º┘ä╪¡'
      } else if (TEMP_EMAIL_DOMAINS.includes(emailDomain)) {
