          e.birthdate = '┘è╪¼╪¿ ╪ú┘å ┘è┘â┘ê┘å ╪╣┘à╪▒┘â 13 ╪╣╪º┘à╪º┘ï ╪╣┘ä┘ë ╪º┘ä╪ú┘é┘ä'
        }
