    async function load() {
      const user = await ensureAuthenticated()
      if (!user) { router.push('/auth/login'); return }
      const { data } = await (supabase.from('profiles') as any).select('*').eq('id', user.id).single()
      if (data) {
        setAvatarBgColor((data as any).avatar_bg_color || '#8B5CF6')
        setAvatarType((data as any).avatar_type || (data.avatar_url ? 'image' : 'color'))

        // Sync to global store if empty
        if (!userName) setUserName(data.display_name || '')
      }
      setLoading(false)
    }
    load()
  }, [router, supabase])

  const handleSaveName = async () => {
    if (!profile || !displayName) return
    setSaving(true)
    setNameError(null)

    // Check uniqueness
    const { data: existing } = await (supabase.from('profiles') as any)
      .select('id')
      .eq('display_name', displayName)
      .neq('id', profile.id)
      .single()

    if (existing) {
