      setSaving(false)
      return
    }

    const { error } = await (supabase.from('profiles') as any)
      .update({ display_name: displayName })
      .eq('id', profile.id)

    if (!error) {
       localStorage.setItem(`display_name_${profile.id}`, displayName)
       setUserName(displayName) // Update global store
    }
    setSaving(false)
  }

