    if (newPassword !== confirmPassword) {
      setPassMessage({ type: 'error', text: isRtl ? '┘â┘ä┘à╪º╪¬ ╪º┘ä┘à╪▒┘ê╪▒ ╪║┘è╪▒ ┘à╪¬╪╖╪º╪¿┘é╪⌐' : 'Passwords do not match' })
