              transition={{ duration: 0.6, delay: i * 0.08, ease: [0.16, 1, 0.3, 1] }}
              className="relative flex items-start gap-6 mb-12 last:mb-0"
              style={{ flexDirection: isRight ? 'row' : 'row-reverse', textAlign: isRight ? 'right' : 'left' }}
