import toast from 'react-hot-toast'
import Mascot from '@/components/Mascot'

const CATEGORIES = [
  { id: 'intro', label: '╪º┘ä╪¬╪▒╪¡┘è╪¿ (Intro)' },
  { id: 'idle', label: '╪º┘ä╪º┘å╪¬╪╕╪º╪▒ (Idle)' },
  { id: 'correct', label: '╪Ñ╪¼╪º╪¿╪⌐ ╪╡╪¡┘è╪¡╪⌐ (Correct)' },
  { id: 'wrong', label: '╪Ñ╪¼╪º╪¿╪⌐ ╪«╪º╪╖╪ª╪⌐ (Wrong)' },
  { id: 'punishment', label: '╪╣┘é╪º╪¿ (Punishment)' },
