                style={{
                  background: `linear-gradient(135deg, ${theme.colors.primary}, ${theme.colors.accent})`,
                  color: '#fff',
                  boxShadow: `0 2px 12px ${theme.colors.primary}44`,
                }}
              >
                ╪º╪¡╪¬┘ü╪╕ ╪¿╪º┘ä╪½┘è┘à Γ£ô
              </button>
            </div>
          </div>
        </motion.div>
      )}
