              <h3 className="text-xl font-black mb-1 truncate" style={{ color: 'var(--text-primary)' }}>{creation.name}</h3>
              <p className="text-[9px] font-bold opacity-30 uppercase tracking-[0.2em] mb-8" style={{ color: 'var(--text-secondary)' }}>
                {creation.categories.length} {isRtl ? '┘ü╪ª╪º╪¬' : 'Categories'} ΓÇó {new Date(creation.createdAt).toLocaleDateString(lang === 'AR' ? 'ar-EG' : 'en-US')}
              </p>

              <button 
                disabled={launching === creation.id}
                onClick={() => handlePlay(creation)}
                className="w-full py-4 rounded-2xl bg-white text-black font-black text-[10px] uppercase tracking-[0.3em] hover:scale-[1.02] active:scale-95 transition-all shadow-xl disabled:opacity-50"
              >
                {launching === creation.id ? (isRtl ? '╪¼╪º╪▒┘è ╪º┘ä╪¬╪¡┘à┘è┘ä...' : 'Launching...') : (isRtl ? '╪º╪¿╪»╪ú ╪º┘ä┘ä╪╣╪¿ ╪º┘ä╪ó┘å' : 'Play Now')}
              </button>
            </div>
          </div>
        ))}
      </div>
    </motion.section>
  )
}

'use client'
// ΓöÇΓöÇΓöÇ context/ThemeContext.tsx ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Provides the active theme to the entire app.

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
  ReactNode,
  Suspense,
} from 'react'
import { useSearchParams } from 'next/navigation'
import { Theme, ThemeId } from '@/types/theme'
import { themes, THEME_STORAGE_KEY, THEME_SESSION_KEY } from '@/lib/themes'

// ΓöÇΓöÇΓöÇ Context shape ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export interface ThemeContextValue {
  /** The fully resolved Theme object */
  theme: Theme
  /** Just the ID string ΓÇö useful for conditional rendering */
  themeId: ThemeId
  /**
   * Switch themes programmatically.
   * @param id      - Target theme ID
   * @param persist - If true (default) saves to localStorage
   */
  setTheme: (id: ThemeId, persist?: boolean) => void
  /** True when the current theme came from a ?theme= URL param */
  isFromSpecialLink: boolean
  /** Persist the current special-link theme to localStorage */
  keepTheme: () => void
  /** Revert to the user's previously saved theme (or default) */
  revertTheme: () => void
}

const defaultCtx: ThemeContextValue = {
  theme: themes.default,
  themeId: 'default',
  setTheme: () => {},
  isFromSpecialLink: false,
  keepTheme: () => {},
  revertTheme: () => {},
}

const ThemeContext = createContext<ThemeContextValue>(defaultCtx)

// ΓöÇΓöÇΓöÇ Inner component ΓÇö reads URL search params (needs Suspense above it) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ThemeUrlReader({
  onThemeFromUrl,
}: {
  onThemeFromUrl: (id: ThemeId) => void
}) {
  const searchParams = useSearchParams()
  // Track last-handled value so rapid re-renders don't re-trigger
  const lastHandled = useRef<string | null>(null)

  useEffect(() => {
    const urlTheme = searchParams.get('theme') as ThemeId | null
    if (urlTheme && themes[urlTheme] && urlTheme !== lastHandled.current) {
      lastHandled.current = urlTheme
      onThemeFromUrl(urlTheme)
    }
  }, [searchParams, onThemeFromUrl])

  return null
}

// ΓöÇΓöÇΓöÇ ThemeProvider ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export function ThemeProvider({ children }: { children: ReactNode }) {
  const [themeId, setThemeId] = useState<ThemeId>('default')
  const [isFromSpecialLink, setIsFromSpecialLink] = useState(false)
  const [initialized, setInitialized] = useState(false)

  // ΓöÇΓöÇ Read saved preference or URL param on first mount ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    // 1. Check URL first
    const urlParams = new URLSearchParams(window.location.search)
    const urlTheme = urlParams.get('theme') as ThemeId | null

    if (urlTheme && themes[urlTheme]) {
      setThemeId(urlTheme)
      // If it's different from saved, trigger special link state
      const saved = localStorage.getItem(THEME_STORAGE_KEY) as ThemeId | null
      if (urlTheme !== saved) {
        setIsFromSpecialLink(true)
        sessionStorage.setItem(THEME_SESSION_KEY, urlTheme)
      }
    } else {
      // 2. Check localStorage
      const saved = localStorage.getItem(THEME_STORAGE_KEY) as ThemeId | null
      if (saved && themes[saved]) {
        setThemeId(saved)
      }
    }
    setInitialized(true)
  }, [])

  // ΓöÇΓöÇ Apply CSS variables & background whenever theme changes ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    if (!initialized) return
    const t = themes[themeId] ?? themes.default

    const root = document.documentElement
    Object.entries(t.cssVars).forEach(([k, v]) => root.style.setProperty(k, v))
    document.body.style.backgroundColor = t.colors.background
    root.setAttribute('data-theme', themeId)
  }, [themeId, initialized])

  // ΓöÇΓöÇ Handler called by ThemeUrlReader ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleThemeFromUrl = useCallback((urlThemeId: ThemeId) => {
    const saved = localStorage.getItem(THEME_STORAGE_KEY) as ThemeId | null
    setThemeId(urlThemeId)
    if (urlThemeId !== saved) {
      // The user arrived via a special link ΓåÆ show the banner
      setIsFromSpecialLink(true)
      sessionStorage.setItem(THEME_SESSION_KEY, urlThemeId)
    }
  }, [])

  // ΓöÇΓöÇ Public API ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const setTheme = useCallback((id: ThemeId, persist = true) => {
    if (!themes[id]) return
    setThemeId(id)
    setIsFromSpecialLink(false)
    if (persist) localStorage.setItem(THEME_STORAGE_KEY, id)
  }, [])

  const keepTheme = useCallback(() => {
    localStorage.setItem(THEME_STORAGE_KEY, themeId)
    setIsFromSpecialLink(false)
    sessionStorage.removeItem(THEME_SESSION_KEY)
  }, [themeId])

  const revertTheme = useCallback(() => {
    setIsFromSpecialLink(false)
    sessionStorage.removeItem(THEME_SESSION_KEY)
    const saved = localStorage.getItem(THEME_STORAGE_KEY) as ThemeId | null
    setThemeId(saved && themes[saved] ? saved : 'default')
  }, [])

  return (
    <ThemeContext.Provider
      value={{
        theme: themes[themeId] ?? themes.default,
        themeId,
        setTheme,
        isFromSpecialLink,
        keepTheme,
        revertTheme,
      }}
    >
      {/* ThemeUrlReader is wrapped in its own Suspense so the rest of the
          app renders immediately ΓÇö no loading state needed at root level */}
      <Suspense fallback={null}>
        <ThemeUrlReader onThemeFromUrl={handleThemeFromUrl} />
      </Suspense>
      {children}
    </ThemeContext.Provider>
  )
}

