export async function getAppSettings<T>(
  key: string,
  defaults: T,
  supabase: any,
): Promise<T> {
  try {
    const { data } = await (supabase.from('app_settings') as any)
      .select('value')
      .eq('key', key)
      .single()
    if (data?.value) return { ...defaults, ...(data.value as object) } as T
  } catch {
    // Table may not exist yet ΓÇö return defaults silently
  }
  return defaults
}

