    if (teamsError) throw new Error(teamsError.message)
    if (!sessionCats || sessionCats.length === 0) throw new Error('┘ä┘à ┘è╪¬┘à ╪º╪«╪¬┘è╪º╪▒ ┘ü╪ª╪º╪¬')
    if (!teams || teams.length < 2)              throw new Error('┘è╪¼╪¿ ╪Ñ╪╢╪º┘ü╪⌐ ┘ü╪▒┘è┘é┘è┘å ╪╣┘ä┘ë ╪º┘ä╪ú┘é┘ä')

    const questionsPerTeam = 3          // 1 easy + 1 medium + 1 hard
    const minPerDiff = teams.length

